module RefModule(  
    input clk,  
    input signal_in,  
    output reg signal_out  
);  
    reg obf_signal_in_d; // Delayed version of the input signal  

    always @(posedge clk) begin  
        obf_signal_in_d <= signal_in;  
        signal_out <= (signal_in && !obf_signal_in_d);  
    end  
endmodule
